    // for now; a proper Mutex-guarded console arrives with the kernel heap
    // in Phase 2.
    let mut uart = arch::Uart::new();
    let _ = writeln!(uart);
    let _ = writeln!(uart, "!!! KERNEL PANIC: {info}");
    arch::halt()
}

