// Assembles the per-arch entry path and exception vectors into the kernel.
//
// .S files go through the C preprocessor + assembler via the `cc` crate.
// CLAUDE.md mandates that multi-instruction assembly lives in .S files (not
// `core::arch::global_asm!`), so this is the only seam between the build
// system and the kernel's assembly.

fn main() {
    let arch =
        std::env::var("CARGO_CFG_TARGET_ARCH").expect("CARGO_CFG_TARGET_ARCH unset");

    match arch.as_str() {
        "aarch64" => {
            let files = ["src/arch/aarch64/entry.S", "src/arch/aarch64/vectors.S"];
            for f in &files {
                println!("cargo:rerun-if-changed={f}");
            }
            println!("cargo:rerun-if-changed=src/arch/aarch64/linker.ld");
            cc::Build::new()
                .compiler("clang")
                .flag("--target=aarch64-unknown-none")
                .files(&files)
                .compile("kernel_arch_aarch64");
        }
        "x86_64" => {
            // Phase 8 territory -- nothing to assemble yet.
        }
        other => panic!("unsupported target arch: {other}"),
    }
}

