//! Minimal PL011 UART driver for early kernel output.
//!
//! Targets the QEMU `virt` machine, where the PL011 MMIO base is fixed at
//! `0x0900_0000`. QEMU pre-initializes the controller for 8-N-1 / 115200,
//! so we only need to poll the TX-FIFO-full flag and write the data
//! register. A proper driver (with init, interrupts, RX, and per-arch base
//! discovery from the device tree) lands in Phase 6 alongside virtio-console.

use core::fmt;
use core::ptr::{read_volatile, write_volatile};

const PL011_BASE: usize = 0x0900_0000;
const DR_OFFSET: usize = 0x00;
const FR_OFFSET: usize = 0x18;
const FR_TXFF: u32 = 1 << 5;

pub struct Pl011 {
    base: *mut u32,
}

impl Pl011 {
    pub const fn new() -> Self {
        Self {
            base: PL011_BASE as *mut u32,
        }
    }

    pub fn putc(&self, c: u8) {
        // SAFETY: PL011 MMIO is fixed at 0x0900_0000 on QEMU virt; Limine
        // sets up device-memory mappings before handoff. Polling FR.TXFF
        // before writing DR is the documented send sequence (ARM PL011 TRM
        // r1p5 section 3.3).
        unsafe {
            let fr = self.base.byte_add(FR_OFFSET);
            while read_volatile(fr) & FR_TXFF != 0 {}
            let dr = self.base.byte_add(DR_OFFSET);
            write_volatile(dr, c as u32);
        }
    }
}

impl fmt::Write for Pl011 {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        for b in s.bytes() {
            if b == b'\n' {
                self.putc(b'\r');
            }
            self.putc(b);
        }
        Ok(())
    }
}

