extern "C" fn kmain() -> ! {
    // Resolve the UART MMIO virtual address before any output. Under Limine
    // protocol revision 3 on aarch64, device memory is not identity-mapped;
    // we reach PL011 through HHDM (or fall back to the physical address if
    // the bootloader didn't populate the response, which would still work
