// MINIX 4 Microkernel
#![no_std]
#![no_main]

mod arch;
mod panic;
mod uart;

use core::fmt::Write;

#[unsafe(no_mangle)]
extern "C" fn kmain() -> ! {
    // Resolve the UART MMIO virtual address before any output. Under Limine
    // protocol revision 3 on aarch64, device memory is not identity-mapped;
    // we reach PL011 through HHDM (or fall back to the physical address if
    // the bootloader didn't populate the response, which would still work
    // on platforms that identity-map low memory).
    let hhdm = arch::limine_hhdm_offset().unwrap_or(0);
    arch::set_uart_base(hhdm as usize + arch::PL011_PHYS_BASE);

    arch::init();

    let mut con = uart::Uart::new();
    let _ = writeln!(con, "MINIX 4 booting on aarch64");

    if arch::limine_base_revision_supported() {
        let _ = writeln!(con, "HHDM offset: {hhdm:#018x}");
    } else {
        let _ = writeln!(
            con,
            "Limine base revision unsupported (loader is too old)"
        );
    }

    arch::halt()
}

